//
import { getVal } from '../../../utils/zcutils';
import { effects } from '../../../effects/zceffects';

function getImage(_, applied) {
    let { context, defsPath = '', rendererMode = 'svg' } = _;
    let { url, width, height, x = 0, y = 0 } = applied,
        _rendererMode = rendererMode === 'base64' ? 'svg' : rendererMode;

    return (d, i) => {
        let prop = {
                name: getVal(url, [d, i]),
                width: getVal(width, [d, i]),
                height: getVal(height, [d, i]),
                x: getVal(x, [d, i]),
                y: getVal(y, [d, i]),
                mode: _rendererMode,
                context
            },
            imageEle = effects.get(effects[`${_rendererMode}_patterns`], 'imageFill', prop, { renderTo: context });

        return rendererMode === 'svg' ? `url(${defsPath}#${imageEle})` : imageEle;
    };
}

export { getImage };
